const ctx = $('Merge With Existing Lead1').first().json;
const stage = ctx.nurture_stage || 'ask_name';
const style = ctx.reply_style || 'en';
const mode = ctx.reply_mode || 'chat';

const NIOS_KNOWLEDGE = `NIOS / Skillvard knowledge (use only when relevant; never dump everything):

TOC / Credit transfer:
- Only for students who failed regular school within last 5 years
- Can transfer max 2 passed subjects to NIOS
- Need original failed certificate in hand
- Plus Two needs 5 subjects total → transfer 2 + write 3 new ones
- New certificate will show all 5

Exams:
- Fully offline
- Center near Aadhaar address

Approvals:
- PSC, UPSC, NEET, abroad — approved

Fees / duration:
- Do NOT invent exact fees or month counts
- Say counsellor will confirm exact fee and timeline shortly`;

const stageGoal = {
  ask_name: 'You do NOT know their name yet. Warmly greet and ask ONLY for their name. Do not use any guessed name from WhatsApp profile.',
  ask_qualification: 'You know their name. Ask ONLY whether they want Plus Two or 10th/SSLC admission through NIOS.',
  ask_pass_fail: 'Ask ONLY: did they fail an exam earlier, OR is this their first time attempting?',
  ask_stream: 'Ask ONLY which stream: Science, Commerce, or Arts. Put each option on its own line.',
  ask_failed_subjects: 'Ask ONLY how many subjects failed and which ones.',
  ask_certificate: 'Ask ONLY if they have the original failed mark sheet (needed for TOC). One short reason is fine.',
  ask_place: 'Ask ONLY which district/place they are from in Kerala.',
  complete: 'Profile is complete. Thank them briefly and say counsellor will guide next steps. Offer to take doubts.'
}[stage] || 'Continue the admission conversation naturally with ONE clear next question.';

const styleLine = style === 'ml'
  ? 'Write in simple Malayalam script.'
  : style === 'manglish'
    ? 'Write in natural Manglish (casual Kerala WhatsApp mix of English + Malayalam roman).'
    : 'Write in simple clear English.';

const systemPrompt = `You are a real admission counsellor at Skillvard NIOS, Kerala, texting on WhatsApp.

Goal: natural, logical lead nurture. Collect details step by step, answer doubts when asked, never sound like a form bot.

${styleLine}

HARD RULES
- NEVER use WhatsApp profile/display name. Only use a name if it is listed under Already known.
- Ask ONE main thing at a time (unless briefly answering a question first).
- If student asked a question (fees, months, TOC, exams, etc.), answer that first in 2-4 short lines, THEN ask the current stage question.
- If they refuse name or reply oddly, soft retry — do not paste the same line again.
- Never dump brochure paragraphs.
- Short lines. Blank line between sections.
- Max 90 words.
- No emojis. No markdown. No bullet symbols.
- Never invent exact fees or course month counts.
- Sound human — like a counsellor texting, not a chatbot.
- Return ONLY the WhatsApp message text.

CURRENT STAGE GOAL
${stageGoal}

${NIOS_KNOWLEDGE}`;

const known = [
  ctx['Student Name'] ? `Name: ${ctx['Student Name']}` : null,
  ctx['Class/Level'] ? `Class/Level: ${ctx['Class/Level']}` : null,
  ctx.Stream ? `Stream: ${ctx.Stream}` : null,
  ctx['Exam Result'] ? `Exam result: ${ctx['Exam Result']}` : null,
  ctx['Subjects Failed'] ? `Failed subjects: ${ctx['Subjects Failed']}` : null,
  ctx['Has Certificate'] ? `Has certificate: ${ctx['Has Certificate']}` : null,
  ctx.Place ? `Place: ${ctx.Place}` : null
].filter(Boolean).join('\n');

const userPrompt = `Stage: ${stage}
Mode: ${mode}
Style: ${style}

Already known (do not re-ask these):
${known || 'Nothing yet — you do NOT know their name'}

Recent chat:
${ctx.chat_history || '(first message)'}

Student just said:
${ctx.latest_message}

Write the next WhatsApp reply.`;

return [{
  json: {
    phone: ctx.Phone,
    nurture_stage: stage,
    reply_mode: mode,
    reply_style: style,
    openai_body: {
      model: 'gpt-4o',
      temperature: 0.7,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ]
    }
  }
}];

const ctx = $('Build Nurture Prompt').first().json;
const merge = $('Merge With Existing Lead1').first().json;
const aiRaw = $input.first().json;

let reply = aiRaw.choices?.[0]?.message?.content?.trim() || '';
reply = reply.replace(/^["']|["']$/g, '').trim();

// Soft fallback only if model returns empty
if (!reply) {
  const style = merge.reply_style || 'en';
  const stage = merge.nurture_stage || 'ask_name';
  if (stage === 'ask_name') {
    reply = style === 'ml'
      ? 'ഹായ്,\n\nSkillvard NIOS നിന്നാണ്.\n\nനിങ്ങളുടെ പേര് പറയാമോ?'
      : style === 'manglish'
        ? 'Hi,\n\nSkillvard NIOS aanu.\n\nNingalude peru parayamo?'
        : 'Hi,\n\nThanks for reaching out to Skillvard NIOS.\n\nMay I know your name?';
  } else {
    reply = style === 'ml'
      ? 'ശരി, ഒരു നിമിഷം.\n\nഈ വിവരം ഒന്ന് കൂടി പറയാമോ?'
      : style === 'manglish'
        ? 'Okay, one second.\n\nEe detail onnu koode parayamo?'
        : 'Okay, one second.\n\nCould you share that detail once more?';
  }
}

// Break accidental long paragraphs
if (reply && !reply.includes('\n') && reply.length > 140) {
  reply = reply
    .replace(/\. ([A-Z\u0D05-\u0D7F])/g, '.\n\n$1')
    .replace(/\? ([A-Z\u0D05-\u0D7F])/g, '?\n\n$1');
}

const wait_seconds = Math.floor(Math.random() * 16) + 8;

return [{
  json: {
    phone: ctx.phone,
    reply_text: reply,
    nurture_stage: merge.nurture_stage,
    reply_style: merge.reply_style,
    wait_seconds
  }
}];

const normalized = $('Normalize Message1').first().json;
const historyItems = $('Get Chat History1').all();

const history = historyItems
  .map((item) => item.json)
  .sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp))
  .map((row) => `[${row.timestamp}] ${row.direction}: ${row.message}`)
  .join('\n');

const systemPrompt = `You are a CRM assistant for Skillvard NIOS, Kerala (NIOS Plus Two admission coaching).

Extract lead information from WhatsApp conversations. Return ONLY valid JSON with these keys:
{
  "student_name": string | null,
  "alternate_phone": string | null,
  "class_level": string | null,
  "stream": string | null,
  "exam_result": "fail" | "first_attempt" | "appearing" | null,
  "subjects_failed": string[] | null,
  "subjects_count": number | null,
  "has_certificate": "yes" | "no" | null,
  "place": string | null,
  "price_disclosed": string | null,
  "intent": "new_inquiry" | "fee_inquiry" | "demo_request" | "follow_up" | "not_interested" | "enrolled" | "other",
  "lead_status": "New" | "Contacted" | "Interested" | "Follow-up" | "Lost" | "Enrolled",
  "lost_reason": string | null,
  "next_followup_days": number | null,
  "remarks": string
}

Rules:
- student_name: ONLY when the student explicitly tells their name in a chat message (e.g. replies "Amna" after being asked, or says "I am Rahul"). NEVER use the WhatsApp display/profile name. If they only said hi/hello, return null.
- class_level: e.g. Plus Two, 12th, 10th, SSLC. If counsellor asked a yes/no question about Plus Two and student replied yes/yeah/yep, set class_level to Plus Two.
- stream: Science, Commerce, Arts. If student replies with just one of these words, set stream accordingly.
- exam_result: "fail" if student failed a previous board exam; "first_attempt" if this is their first time attempting the exam. Infer from context (e.g. "first time", "no I didn't fail", "failed", "yes I failed").
- has_certificate: yes/no — whether they have the original failed mark sheet/certificate in hand (needed for TOC)
- place: district or town in Kerala
- subjects_failed: array like ["Physics", "Chemistry"]
- subjects_count: number of failed subjects mentioned
- price_disclosed: fee amount if discussed, otherwise "No"
- remarks: 2-3 sentence summary of the FULL conversation history
- Use null for unknown fields
- lead_status must align with intent`;

const userPrompt = `Phone: ${normalized.phone}

Conversation history:
${history || `[${normalized.timestamp}] inbound: ${normalized.message}`}

Latest message:
${normalized.message}

Note: WhatsApp profile name is NOT the student name — ignore it completely.`;

return [{
  json: {
    ...normalized,
    openai_body: {
      model: 'gpt-4o',
      temperature: 0.2,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ]
    }
  }
}];

const normalized = $('Build AI Prompt1').first().json;
const aiRaw = $input.first().json;

let extracted = {};
try {
  const content = aiRaw.choices?.[0]?.message?.content || '{}';
  extracted = JSON.parse(content);
} catch (e) {
  extracted = {
    student_name: null,
    intent: 'other',
    lead_status: 'Contacted',
    remarks: normalized.message
  };
}

const historyItems = $('Get Chat History1').all().map((item) => item.json);

function confirmStudentName(name, history, whatsappName) {
  const n = String(name || '').trim();
  if (!n || n.length < 2) return '';
  if (/LLP|TECHNOLOGIES|PVT|LTD|COMPANY|SHOP|STORE|BASE OF/i.test(n)) return '';
  if (/^(hi|hello|hey|student|user|there|ok|yes|no)$/i.test(n)) return '';

  const sorted = [...historyItems].sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));
  const inbound = sorted.filter((r) => r.direction === 'inbound').map((r) => String(r.message || '').trim());
  const nameLower = n.toLowerCase();
  const waLower = String(whatsappName || '').trim().toLowerCase();
  const askedForName = sorted.some((r) =>
    r.direction === 'outbound' && /(your name|know your name|may i know|peru|പേര്)/i.test(String(r.message || ''))
  );

  for (const msg of inbound) {
    const m = msg.toLowerCase();
    if (/^(my name is|i am|i'm|im |ente peru|enikku peru|nan |call me)/i.test(msg)) {
      if (m.includes(nameLower) || nameLower.split(/\s+/).some((part) => part.length > 2 && m.includes(part))) return n;
    }
    if (askedForName && msg.length <= 35 && /^[a-zA-Z\u0D00-\u0D7F][\w\u0D00-\u0D7F\s.'-]*$/i.test(msg)) {
      const msgLower = msg.toLowerCase();
      if (msgLower === nameLower || nameLower.startsWith(msgLower) || msgLower.startsWith(nameLower.split(' ')[0])) return msg.trim();
    }
  }

  if (waLower && (nameLower === waLower || waLower.startsWith(nameLower) || nameLower === waLower.split(/\s+/)[0])) return '';
  return '';
}

const confirmedName = confirmStudentName(extracted.student_name, historyItems, normalized.whatsapp_name);

function inferFromContext(data, history, latestMsg) {
  const sorted = [...history].sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));
  const lastOutbound = [...sorted].reverse().find((r) => r.direction === 'outbound');
  const lastOut = String(lastOutbound?.message || '').toLowerCase();
  const latest = String(latestMsg || '').trim().toLowerCase();
  const out = { ...data };

  if (!out.class_level && /^(yes|yeah|yep|correct|y)$/i.test(latest)) {
    if (/plus two|12th|plus 2/i.test(lastOut)) out.class_level = 'Plus Two';
    else if (/10th|sslc|tenth/i.test(lastOut)) out.class_level = '10th';
  }

  if (!out.exam_result) {
    if (/fail|failed/i.test(latest) || (latest === 'yes' && /did you fail|fail your exam/i.test(lastOut))) {
      out.exam_result = 'fail';
    } else if (/first time|first attempt|first/i.test(latest) || (latest === 'no' && /did you fail|first time/i.test(lastOut))) {
      out.exam_result = 'first attempt';
    }
  }

  if (!out.stream && /^(science|commerce|arts)$/i.test(latest)) {
    out.stream = latest.charAt(0).toUpperCase() + latest.slice(1);
  }

  return out;
}

extracted = inferFromContext(extracted, historyItems, normalized.message);

const intentMap = {
  new_inquiry: 'New',
  fee_inquiry: 'Interested',
  demo_request: 'Interested',
  follow_up: 'Follow-up',
  not_interested: 'Lost',
  enrolled: 'Enrolled',
  other: 'Contacted'
};

const leadStatus = extracted.lead_status || intentMap[extracted.intent] || 'Contacted';
const subjects = Array.isArray(extracted.subjects_failed)
  ? extracted.subjects_failed.filter(Boolean)
  : [];

const followupDays = Number(extracted.next_followup_days);
const nextFollowUp = Number.isFinite(followupDays) && followupDays > 0
  ? new Date(Date.now() + followupDays * 86400000).toISOString().slice(0, 10)
  : '';

const today = new Date().toISOString().slice(0, 10);
const lastContacted = String(normalized.timestamp).slice(0, 10);

function normalizePhone(value) {
  const digits = String(value || '').replace(/\D/g, '');
  if (digits.length === 10) return '91' + digits;
  return digits;
}

function normalizeExamResult(value) {
  const v = String(value || '').trim().toLowerCase();
  if (!v) return '';
  if (/first|first time|first attempt|never|fresh/i.test(v)) return 'First attempt';
  if (/fail|failed|supplementary|compartment/.test(v)) return 'Fail';
  if (/appear|studying|writing/i.test(v)) return 'Appearing';
  return value;
}

function normalizeYesNo(value) {
  const v = String(value || '').trim().toLowerCase();
  if (!v) return '';
  if (/^(yes|y|ഉണ്ട്|ആണ്|und|unde|correct|ok)$/.test(v)) return 'Yes';
  if (/^(no|n|ഇല്ല|illa|negative)$/.test(v)) return 'No';
  return value;
}

const phone = normalizePhone(normalized.phone);

return [{
  json: {
    phone,
    lead_id: `WA-${phone}`,
    date: today,
    student_name: confirmedName,
    alternate_phone: extracted.alternate_phone ? normalizePhone(extracted.alternate_phone) : '',
    class_level: extracted.class_level || '',
    stream: extracted.stream || '',
    exam_result: normalizeExamResult(extracted.exam_result),
    subjects_failed: subjects.join(', '),
    subjects_count: extracted.subjects_count ?? (subjects.length || ''),
    has_certificate: normalizeYesNo(extracted.has_certificate),
    place: extracted.place || '',
    source: 'WhatsApp',
    price_disclosed: extracted.price_disclosed || 'No',
    lead_status: leadStatus,
    lost_reason: extracted.lost_reason || '',
    assigned_to: '',
    last_contacted: lastContacted,
    next_follow_up: nextFollowUp,
    remarks: extracted.remarks || normalized.message
  }
}];

const lead = $('Map to CRM Fields1').first().json;
const rows = $input.all().map((item) => item.json);
const history = $('Get Chat History1').all().map((item) => item.json);
const normalized = $('Normalize Message1').first().json;

function normalizePhone(value) {
  const digits = String(value || '').replace(/\D/g, '');
  if (digits.length === 10) return '91' + digits;
  return digits;
}

function phoneKey(value) {
  return normalizePhone(value).slice(-10);
}

function isRealName(name, history, whatsappName) {
  const n = String(name || '').trim();
  if (!n || n.length < 2) return false;
  if (/LLP|TECHNOLOGIES|PVT|LTD|COMPANY|SHOP|STORE|BASE OF/i.test(n)) return false;
  if (/^(hi|hello|hey|student|user|there|ok|yes|no|haloo|hallo|hai)$/i.test(n)) return false;

  const sorted = [...history].sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));
  const inbound = sorted.filter((r) => r.direction === 'inbound').map((r) => String(r.message || '').trim());
  const nameLower = n.toLowerCase();
  const waLower = String(whatsappName || '').trim().toLowerCase();
  const askedForName = sorted.some((r) =>
    r.direction === 'outbound' && /(your name|know your name|may i know|peru|പേര്)/i.test(String(r.message || ''))
  );

  for (const msg of inbound) {
    const m = msg.toLowerCase();
    if (/^(my name is|i am|i'm|im |ente peru|enikku peru|nan |call me)/i.test(msg)) {
      if (m.includes(nameLower) || nameLower.split(/\s+/).some((part) => part.length > 2 && m.includes(part))) return true;
    }
    if (askedForName && msg.length <= 40 && /^[a-zA-Z\u0D00-\u0D7F.][\w\u0D00-\u0D7F\s.'-]*$/i.test(msg)) {
      const msgLower = msg.toLowerCase();
      if (msgLower === nameLower || nameLower.startsWith(msgLower) || msgLower.startsWith(nameLower.split(' ')[0])) return true;
    }
  }

  if (waLower && (nameLower === waLower || waLower.startsWith(nameLower) || nameLower === waLower.split(/\s+/)[0])) return false;
  return false;
}

function detectStyle(latestMsg, chatHistory, remarks) {
  const blob = `${latestMsg}\n${chatHistory || ''}\n${remarks || ''}`.toLowerCase();
  if (/\[lang:ml\]|speaking malayalam|malayalam script|[\u0d00-\u0d7f]/.test(blob)) return 'ml';
  if (/\[lang:manglish\]|speaking manglish|\b(aano|aanu|ningal|njan|enth|parayamo|paranj|tharamoo|ayittundo|illengil|cheythu|mumbu|peru|ethu|ethra|undo|illa|ithinte|onn)\b/i.test(blob)) return 'manglish';
  return 'en';
}

function looksLikeQuestion(msg) {
  const t = String(msg || '').trim();
  if (!t) return false;
  if (/^(hi|hello|hey|haloo|hallo|hai|ok|okay|yes|no|yeah|yep)$/i.test(t)) return false;
  return /\?|how many|how much|cost|fee|fees|price|details|duration|month|months|what about|paranj|tharam|enth|ento|detail|toc|certificate|exam|നമുക്ക്|എന്ത്|എത്ര|ഫീസ്/i.test(t);
}

function isVoiceNote(text) {
  const t = String(text || '').trim().toLowerCase();
  return t === '[voice note]' || t === '[audio]' || t === 'voice note';
}

const targetKey = phoneKey(lead.phone);
let existing = null;

for (const row of rows) {
  const rowKey = phoneKey(row.Phone || row.phone);
  const altKey = phoneKey(row['Alternate Phone'] || row.alternate_phone);
  if ((rowKey && rowKey === targetKey) || (altKey && altKey === targetKey)) {
    existing = row;
    break;
  }
}

const followups = existing
  ? (Number(existing['Follow-ups Count'] || existing.follow_ups_count || 0) + 1)
  : 1;

const pick = (next, prev) => {
  if (next !== null && next !== undefined && String(next).trim() !== '') return next;
  return prev || '';
};

const phone = normalizePhone(existing?.Phone || lead.phone);
const rawName = pick(lead.student_name, existing?.['Student Name']);
const confirmedName = isRealName(rawName, history, normalized.whatsapp_name) ? rawName : '';

let remarks = lead.remarks || existing?.Remarks || '';
const latestLower = String(normalized.message || '').toLowerCase();
if (/speaking malayalam|malayalam script/.test(latestLower) && !/\[lang:ml\]/.test(remarks)) {
  remarks = `${remarks} [lang:ml]`.trim();
}
if (/speaking manglish/.test(latestLower) && !/\[lang:manglish\]/.test(remarks)) {
  remarks = `${remarks} [lang:manglish]`.trim();
}

const merged = {
  'Lead ID': existing?.['Lead ID'] || lead.lead_id,
  'Date': existing?.Date || lead.date,
  'Student Name': confirmedName,
  'Phone': phone,
  'Alternate Phone': pick(lead.alternate_phone, existing?.['Alternate Phone']),
  'Class/Level': pick(lead.class_level, existing?.['Class/Level']),
  'Stream': pick(lead.stream, existing?.['Stream']),
  'Exam Result': pick(lead.exam_result, existing?.['Exam Result']),
  'Subjects Failed': pick(lead.subjects_failed, existing?.['Subjects Failed']),
  'Subjects Count': pick(lead.subjects_count, existing?.['Subjects Count']),
  'Has Certificate': pick(lead.has_certificate, existing?.['Has Certificate']),
  'Place': pick(lead.place, existing?.['Place']),
  'Source': existing?.Source || lead.source,
  'Price Disclosed': pick(lead.price_disclosed, existing?.['Price Disclosed']),
  'Lead Status': lead.lead_status || existing?.['Lead Status'] || 'Contacted',
  'Lost Reason': pick(lead.lost_reason, existing?.['Lost Reason']),
  'Assigned To': existing?.['Assigned To'] || '',
  'Last Contacted': lead.last_contacted,
  'Next Follow-up': pick(lead.next_follow_up, existing?.['Next Follow-up']),
  'Follow-ups Count': followups,
  'Remarks': remarks
};

function getNurtureStage(data) {
  const name = String(data['Student Name'] || '').trim();
  const level = String(data['Class/Level'] || '').trim();
  const stream = String(data['Stream'] || '').trim();
  const examResult = String(data['Exam Result'] || '').trim().toLowerCase();
  const subjectsFailed = String(data['Subjects Failed'] || '').trim();
  const hasCert = String(data['Has Certificate'] || '').trim();
  const place = String(data['Place'] || '').trim();

  if (!name) return 'ask_name';
  if (!level) return 'ask_qualification';
  if (!examResult) return 'ask_pass_fail';
  if (/plus two|12th|xii|plus 2|\+2|twelfth/i.test(level) && !stream) return 'ask_stream';
  if (examResult.includes('fail') && !subjectsFailed) return 'ask_failed_subjects';
  if (examResult.includes('fail') && !hasCert) return 'ask_certificate';
  if (!place) return 'ask_place';
  return 'complete';
}

const nurtureStage = getNurtureStage(merged);
const leadStatus = String(merged['Lead Status'] || '').toLowerCase();
const latestMsg = String(normalized.message || '');
const isQuestion = looksLikeQuestion(latestMsg);
const replyStyle = detectStyle(latestMsg, history.map((r) => r.message).join('\n'), remarks);

const sortedHistory = [...history].sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));
const lastOutbound = [...sortedHistory].reverse().find((r) => r.direction === 'outbound');
const lastOutboundText = String(lastOutbound?.message || '');
const lastOutboundAgeMs = lastOutbound ? (Date.now() - new Date(lastOutbound.timestamp).getTime()) : Infinity;

const hasAudioInbound = Boolean(normalized.is_audio) ||
  isVoiceNote(normalized.message) ||
  history.some((r) => r.direction === 'inbound' && isVoiceNote(r.message));

const isEnriched = nurtureStage === 'complete';

if (hasAudioInbound) {
  merged['Lead Status'] = 'Follow-up';
  merged['Remarks'] = `${merged['Remarks'] || ''} [Voice note received - manual follow-up needed]`.trim();
}

// Duplicate protection: same stage template already sent in last 90s and latest msg is not a question
const stageHints = {
  ask_name: /may i know your name|peru parayamo|പേര് പറയാമോ/i,
  ask_qualification: /plus two admission|10th \/ sslc/i,
  ask_pass_fail: /fail your exam earlier|first time attempting|first time attempt/i,
  ask_stream: /which stream|ethu stream|ഏത് stream/i,
  ask_failed_subjects: /how many subjects|ethra subject|എത്ര subject/i,
  ask_certificate: /mark sheet|toc/i,
  ask_place: /which district|ethu district|ഏത് district/i
};
const sameStageRecently =
  !isQuestion &&
  lastOutboundAgeMs < 90000 &&
  stageHints[nurtureStage] &&
  stageHints[nurtureStage].test(lastOutboundText);

let replyMode = 'chat';
if (isQuestion && !isEnriched && !hasAudioInbound) {
  replyMode = 'answer_then_ask';
}

const shouldNurture =
  normalized.direction === 'inbound' &&
  !['lost', 'enrolled'].includes(leadStatus) &&
  !hasAudioInbound &&
  !isEnriched &&
  !sameStageRecently;

const chatHistory = sortedHistory
  .map((row) => `${row.direction}: ${row.message}`)
  .join('\n');

return [{
  json: {
    ...merged,
    should_nurture: shouldNurture,
    nurture_stage: nurtureStage,
    reply_mode: replyMode,
    reply_style: replyStyle,
    has_audio: hasAudioInbound,
    is_enriched: isEnriched,
    latest_message: normalized.message,
    whatsapp_name: normalized.whatsapp_name || '',
    chat_history: chatHistory
  }
}];
